  data-mcs-consequence="Triggers the associated action"
  data-mcs-triggers-event="button:click"
>
  <span class="c-button__label">Button</span>
  <span class="c-button__spinner" hidden aria-hidden="true">
    <svg class="c-icon" viewBox="0 0 24 24" width="16" height="16">
